cat > /tmp/patch_completions.txt << 'EOF'
// CompletionOptions are the options to control shell completion
type CompletionOptions struct {
	// DisableDefaultCmd prevents Cobra from creating a default 'completion' command
	DisableDefaultCmd bool
	// DisableNoDescFlag prevents Cobra from creating the '--no-descriptions' flag
	// for shells that support completion descriptions
	DisableNoDescFlag bool
	// DisableDescriptions turns off all completion descriptions for shells
	// that support them
	DisableDescriptions bool
	// HiddenDefaultCmd makes the default 'completion' command hidden
	HiddenDefaultCmd bool
	// LimitCompletions sets the maximum number of completions to return
	// A value of 0 or negative means no limit
	LimitCompletions int
	// FilterHidden, if true, filters out completions that start with a dot
	FilterHidden bool
}
EOF
cat /tmp/patch_completions.txt

cat > /tmp/setmethods.txt << 'EOF'

// SetLimitCompletions sets the maximum number of completions to return.
// A value of 0 or negative means no limit.
func (c *CompletionOptions) SetLimitCompletions(value int) {
	c.LimitCompletions = value
}

// SetFilterHidden sets whether to filter out completions that start with a dot.
func (c *CompletionOptions) SetFilterHidden(value bool) {
	c.FilterHidden = value
}
EOF
cat /tmp/setmethods.txt

cat > /tmp/helper_functions.txt << 'EOF'
// getCompletionOptions traverses up the command tree to find the
// completion options (LimitCompletions and FilterHidden). It returns the
// limit (0 or negative means no limit) and filterHidden settings.
func getCompletionOptions(cmd *Command) (int, bool) {
	var limit int
	var filterHidden bool

	// Traverse from the current command up to the root
	cmd.VisitParents(func(c *Command) {
		// Use the first non-zero limit found (most specific)
		if limit == 0 && c.CompletionOptions.LimitCompletions != 0 {
			limit = c.CompletionOptions.LimitCompletions
		}
		// Use the first non-default filterHidden found (most specific)
		if !filterHidden && c.CompletionOptions.FilterHidden {
			filterHidden = c.CompletionOptions.FilterHidden
		}
	})

	// Also check the current command itself
	if limit == 0 && cmd.CompletionOptions.LimitCompletions != 0 {
		limit = cmd.CompletionOptions.LimitCompletions
	}
	if !filterHidden && cmd.CompletionOptions.FilterHidden {
		filterHidden = cmd.CompletionOptions.FilterHidden
	}

	return limit, filterHidden
}

// filterHiddenCompletions removes completions that start with a dot.
func filterHiddenCompletions(completions []Completion) []Completion {
	result := make([]Completion, 0, len(completions))
	for _, comp := range completions {
		// Get the completion string (before the TAB if it has a description)
		idx := strings.Index(comp, "\t")
		var completionStr string
		if idx == -1 {
			completionStr = comp
		} else {
			completionStr = comp[:idx]
		}

		// Skip completions that start with a dot
		if !strings.HasPrefix(completionStr, ".") {
			result = append(result, comp)
		}
	}
	return result
}
EOF
cat /tmp/helper_functions.txt

sed -i '583s/return finalCmd, completions, directive, nil/	// Apply LimitCompletions and FilterHidden options
	limit, filterHidden := getCompletionOptions(finalCmd)
	if filterHidden {
		completions = filterHiddenCompletions(completions)
	}
	if limit > 0 \&\& len(completions) > limit {
		completions = completions[:limit]
	}
	return finalCmd, completions, directive, nil/' /workspace/repo/completions.go

